const startTime = Date.now();
let intelLog = [], oppAlerts = [], tavilyNews = [], topOpps = [];
let errors = [];

try { intelLog = $('Get Intel Log').all().map(i => i.json).filter(i => i && Object.keys(i).length > 0 && !i.error); } catch(e) { errors.push('intel_log: ' + e.message); }
try { oppAlerts = $('Get Opportunity Alerts').all().map(i => i.json).filter(i => i && (i.agency || i.solicitation_number)); } catch(e) { errors.push('opp_alerts: ' + e.message); }
try {
  const tavRaw = $('Tavily Defense News').first()?.json;
  if (tavRaw?.results && Array.isArray(tavRaw.results)) {
    tavilyNews = tavRaw.results.map(function(r) {
      var source = 'unknown';
      try { if (r.url) source = new URL(r.url).hostname.replace('www.',''); } catch(e) { source = r.url ? r.url.split('/')[2] || 'unknown' : 'unknown'; }
      return { title: r.title || 'Untitled', url: r.url || '', content: (r.content || '').substring(0, 200), source: source, published: r.published_date || null };
    });
  } else if (tavRaw?.error || (tavRaw?.statusCode && tavRaw.statusCode >= 400)) {
    errors.push('tavily: API error ' + (tavRaw.statusCode || tavRaw.error?.message || 'unknown'));
  } else if (tavRaw && !tavRaw.results) {
    errors.push('tavily: No results field — check TAVILY_API_KEY env var');
  }
} catch(e) { errors.push('tavily: ' + e.message); }
try { topOpps = $('Get Top Opps').all().map(i => i.json).filter(i => i && (i.agency || i.solicitation_number)); } catch(e) { errors.push('top_opps: ' + e.message); }

const totalResults = intelLog.length + oppAlerts.length + tavilyNews.length + topOpps.length;
const durationMs = Date.now() - startTime;

let status, message, actionRequired = null;
if (errors.length > 0 && totalResults === 0) {
  status = 'ERROR';
  message = 'Intel scan failed — ' + errors[0].substring(0, 80) + '. Retry recommended.';
  actionRequired = 'RETRY';
} else if (totalResults === 0) {
  status = 'EMPTY';
  message = 'Scan complete — 0 results. DB may be empty or Tavily key missing.';
} else if (errors.length > 0) {
  status = 'COMPLETE';
  message = 'Partial scan: ' + totalResults + ' items found, ' + errors.length + ' source(s) degraded';
} else {
  status = 'COMPLETE';
  message = 'Intel scan complete — ' + totalResults + ' items from ' + [intelLog.length > 0 ? 'IntelLog(' + intelLog.length + ')' : '', oppAlerts.length > 0 ? 'Opps(' + oppAlerts.length + ')' : '', tavilyNews.length > 0 ? 'OSINT(' + tavilyNews.length + ')' : '', topOpps.length > 0 ? 'Pipeline(' + topOpps.length + ')' : ''].filter(Boolean).join(', ');
}

return [{ json: {
  feed_status: { status: status, message: message.substring(0, 120), timestamp: new Date().toISOString(), estimated_completion: null, action_required: actionRequired, duration_ms: durationMs, errors: errors.length > 0 ? errors : undefined },
  intel_log: intelLog.slice(0, 20),
  opportunity_alerts: oppAlerts.slice(0, 20),
  defense_news: tavilyNews.slice(0, 10),
  top_opportunities: topOpps.slice(0, 10),
  total_results: totalResults
}}];
